-- ====================================\n-- 为用户表添加组织ID字段\n-- ====================================\n\n-- 检查用户表是否存在组织ID字段\nDO $$\nBEGIN\n    -- 检查组织ID字段是否存在\n    IF NOT EXISTS (SELECT FROM information_schema.columns WHERE table_name = 'users' AND column_name = 'organization_id') THEN\n        -- 添加组织ID字段，引用组织单位表的unit_id\n        ALTER TABLE users ADD COLUMN organization_id VARCHAR(50) REFERENCES organizations(unit_id) ON DELETE SET NULL;\n        \n        -- 创建索引以提高查询性能\n        CREATE INDEX IF NOT EXISTS idx_users_organization_id ON users(organization_id);\n        \n        RAISE NOTICE '为用户表添加组织ID字段成功';\n    ELSE\n        RAISE NOTICE '用户表已存在组织ID字段';\n    END IF;\n    \n    -- 为现有用户设置默认组织ID为'root'\n    UPDATE users SET organization_id = 'root' WHERE organization_id IS NULL;\n    \n    RAISE NOTICE '为现有用户设置默认组织ID成功';\nEND $$;\n\n-- 检查用户响应模式是否需要更新\n-- 注意：这部分需要手动更新src/schemas.rs文件\n\nSELECT '用户表添加组织ID字段完成！' AS info;

